import React from 'react';
import Nav from '../components/Nav';
import Text from '../components/Text';
import Banner from '../components/Banner';
import Section from '../components/Section';
import MarkerList from '../components/MarkerList';
import Image from '../components/Image';
import projects from '../data/projects';
import FeedBackCard from '../components/FeedBackCard';
import { getNavItems } from '../data/navItems';
import Article from '../components/Article';
import { useLanguage } from '../i18n/LanguageContext';

export default function AxelNacCase(){
  const { t, lang } = useLanguage();
  const project = projects.find(p => p.id === 'axelnac');
  const title = t('projects.axelnac.title', project.title);
  const tasks = t('pages.axelnac.tasks.items', { returnObjects: true });
  const done = t('pages.axelnac.done.items', { returnObjects: true });
  
  return (
    <div className="min-h-screen">
  <Nav items={getNavItems(t, lang)} />
      <main className="max-w-[1600px] w-full mx-auto pb-1">

        <Section className="pt-12 gap-8">
          <Text variant="h1">{title}</Text>
          <Image
            src={project.thumbnail}
            sources={[
              { srcSet: project.thumbnail_2x, media: "(min-width: 1024px)" }
            ]}
            backgroundColor={project.thumbnailBackground}
            alt={title}
          />
          <Text variant="h4">{t('pages.axelnac.subtitle')}</Text>
        </Section>

        <Section title={t('pages.axelnac.tasks.title')} className="gap-4">
          <div className="grid gap-4 grid-cols-1 xl:grid-cols-3">
            {Array.isArray(tasks) && tasks.map((task, i) => (
              <Banner
                key={i}
                emoji={task.icon}
                title={task.title}
                text={task.text}
              />
            ))}
          </div>
        </Section>

        <Section title={t('pages.axelnac.done.title')} className="gap-4">
          <MarkerList
            className="space-y-2"
            items={done}
          />
        </Section>

        <Section title={t('pages.axelnac.before.title')} className="gap-4">
          <Article>
            <Text variant="p">{t('pages.axelnac.before.main')}</Text>
            <Image
              src="/images/axelnac/was.webp"
              sources={[
                { srcSet: "/images/axelnac/was-2x.webp", media: "(min-width: 1024px)" }
              ]}
              alt={t('pages.axelnac.before.altBefore')}
              shadow
            />
          </Article>
          <Article last>
            <Text variant="p">{t('pages.axelnac.before.constructor1')}</Text>
            <Text variant="p">{t('pages.axelnac.before.constructor2')}</Text>
            <Image
              src="/images/axelnac/2.png"
              alt={t('pages.axelnac.before.altBefore')}
              className='!pb-0'
              shadow 
            />
          </Article>
        </Section>

        <Section title={t('pages.axelnac.after.title')} className="gap-4">
          <Article title={t('pages.axelnac.after.structure.title')}>
            <Text variant="p">{t('pages.axelnac.after.structure.text')}</Text>
            <Image
              src="/images/axelnac/now.webp"
              sources={[
                { srcSet: "/images/axelnac/now-2x.webp", media: "(min-width: 1024px)" }
              ]}
              alt={t('pages.axelnac.after.altAfter')}
              shadow
            />
          </Article>
          <Article>
            <Text variant="p">{t('pages.axelnac.after.grouped')}</Text>
            <Image
              src="/images/axelnac/layout.webp"
              sources={[
                { srcSet: "/images/axelnac/layout-2x.webp", media: "(min-width: 1024px)" }
              ]}
              alt={t('pages.axelnac.after.altAfter')}
              shadow
            />
          </Article>
          <Article title={t('pages.axelnac.after.modes.title')} >
            <div className='flex flex-col lg:flex-row gap-8 items-start'>
              <div className='w-full lg:w-[35%] grid gap-2'>
                <Text variant="p">{t('pages.axelnac.after.modes.text1')}</Text>
                <Text variant="p">{t('pages.axelnac.after.modes.text2')}</Text>
              </div>
              <Image
                src="/images/axelnac/12.gif"
                alt={t('pages.axelnac.after.altAfter')}
                className='w-full lg:w-[65%]'
                shadow
              />
            </div>
            

          </Article>
        </Section>

        <Section title={t('pages.axelnac.constructor.title')} className="gap-4">
          <Article>
              <Text variant="p">{t('pages.axelnac.constructor.main1')}</Text>
              
              <Text variant="p">{t('pages.axelnac.constructor.main2')}</Text>
            
            <Image
              src="/images/axelnac/board.webp"
              sources={[
                { srcSet: "/images/axelnac/board-2x.webp", media: "(min-width: 1024px)" }
              ]}
              alt={t('pages.axelnac.after.altAfter')}
              shadow
            />
            </Article>
            <Article title={t('pages.axelnac.constructor.fields.title')}>
              <Text variant="p">{t('pages.axelnac.constructor.fields.text')}</Text>
              <Image
                src="/images/axelnac/fields.webp"
                sources={[
                  { srcSet: "/images/axelnac/fields-2x.webp", media: "(min-width: 1024px)" }
                ]}
                alt={t('pages.axelnac.after.altAfter')}
              />
            </Article>
            <Article title={t('pages.axelnac.constructor.search.title')}>
              <div className="flex flex-col lg:flex-row gap-8 items-start">
                <Image
                  src="/images/axelnac/6.gif"
                  alt={t('pages.axelnac.after.altAfter')}
                  className="w-full lg:w-1/2 !pb-0"
                  shadow
                />
                <Text variant="p" className="w-full lg:w-1/2">{t('pages.axelnac.constructor.search.text')}</Text>
              </div>
            </Article>   
            <Article title={t('pages.axelnac.constructor.sorting.title')} last>
              <Text variant="p">{t('pages.axelnac.constructor.sorting.text')}</Text>
              <Image
                src="/images/axelnac/sorting.webp"
                sources={[
                  { srcSet: "/images/axelnac/sorting-2x.webp", media: "(min-width: 1024px)" }
                ]}
                alt={t('pages.axelnac.after.altAfter')}
              />     
            </Article>
        </Section>

        <Section title={t('pages.axelnac.result.title')} last className="gap-4">
          <Text variant="p">{t('pages.axelnac.result.text')}</Text>
        </Section>
      </main>
    </div>
  );
}
